import math

def is_special_number(num: int) -> bool:
    s = str(num)
    if s != s[::-1]:
        return False
    count = {}
    for c in s:
        digit = int(c)
        if digit == 0:
            return False
        count[digit] = count.get(digit, 0) + 1
    for d, cnt in count.items():
        if cnt != d:
            return False
    return True

def solve(n: int) -> int:
    current = n + 1
    while True:
        if is_special_number(current):
            return current
        current += 1
